use std::io;
use std::str::FromStr;

use std::io::prelude::*;
use std::io::BufReader;
use std::cmp::{max, min};

fn get_line() -> String {
    let mut input = String::new();
    io::stdin().read_line(&mut input).unwrap();
    input
}

fn get_vec<T>() -> Vec<T>
where T: FromStr,
      <T as FromStr>::Err: std::fmt::Debug,
{
    get_line().split_whitespace().map(|k| k.parse().unwrap()).collect()
}

const N: i64 = 998_244_353;

fn extended_euclid(a: i64, b: i64) -> (i64, i64, i64) {
    if b == 0 {
        (a, 1, 0)
    } else {
        let (d0, x0, y0) = extended_euclid(b, a % b);
        (d0, y0, x0 - a / b * y0)
    }
}

fn main() {
    let s = get_line().trim().to_string();

    let names = vec![
        "Danil",
        "Olya",
        "Slava",
        "Ann",
        "Nikita",
    ];

    let count = names.into_iter()
        .map(|name| s.split(name).count() - 1)
        .sum::<usize>();

    if count == 1 {
        println!("YES");
    } else {
        println!("NO");
    }
}
